window.addEventListener("DOMContentLoaded",()=>{const e=document.querySelector(".tabheader__items"),t=document.querySelectorAll(".tabcontent"),a=document.querySelectorAll(".tabheader__item");function s(){t.forEach(e=>{e.classList.add("hide"),e.classList.remove("show","fade")}),a.forEach(e=>{e.classList.remove("tabheader__item_active")})}function c(e=0){t[e].classList.remove("hide"),t[e].classList.add("show","fade"),a[e].classList.add("tabheader__item_active")}s(),c(),e.addEventListener("click",e=>{const t=e.target;t&&t.closest(".tabheader__item")&&a.forEach((e,a)=>{t==e&&(s(),c(a))})})});